- (* Var *)
  inversion Ht; subst; clear Ht.
  match goal with
  | H: nth_error (G ++ [T]) n = Some U |- _ =>
    destruct (Nat.eqb_spec n (length G));
    [subst n; rewrite (nth_error_app_singleton_r ty G T) in H;
     inversion H; subst; clear H; apply Hs
    | assert (n < length G) as Hlt;
      [pose proof (nth_error_Some_len ty (G ++ [T]) n U H) as Hlen;
       simpl in Hlen;
       destruct (n <? length G) eqn:E;
       [apply Nat.ltb_lt in E; exact E
       |apply Nat.ltb_nlt in E; lia]
      |rewrite (nth_error_app_l ty G [T] n Hlt) in H;
       simpl; apply T_Var; exact H]]
  end.

- (* S_If *)
  inversion Ht'; subst; clear Ht'.
  match goal with
  | H1: has_type [] S' t1 TyBool, H2: has_type [] S' t2 ?Ty, H3: has_type [] S' t3 ?Ty |- _ =>
    destruct (IHHstep TyBool _ H1 Hok' Hlen')
      as [S'' [Hext [Hok'' Ht'']]];
    exists S''; split; [| split]; auto;
    apply (T_If [] S'' t' t2 t3 Ty);
    [exact Ht'' | eapply store_weakening; [exact H2 | eauto] | eapply store_weakening; [exact H3 | eauto]]
  end.

